INSERT INTO projects (id, workspaceId, data) VALUES ('proj-atlas', 'acme', '{"id":"proj-atlas","workspaceId":"acme","title":"Atlas Platform","description":"Ship the first public release of the Atlas humanoid platform — hardware, firmware, fleet coordination, and a customer-facing control plane.","successCriteria":"- 100 beta units shipped to pilot customers\n- p95 motion latency under 200ms\n- 99.5% uptime over rolling 30 days\n- OTA firmware updates verified end-to-end","color":"#0562EF","status":"ACTIVE","tickets":[{"id":"AT-101","title":"Calibrate ankle torque controller","status":"EXECUTING","assignedAgentId":"agent-elena"},{"id":"AT-102","title":"OTA firmware signing pipeline","status":"EXECUTING","assignedAgentId":"agent-priya"},{"id":"AT-103","title":"Vision-language-action benchmark suite","status":"EXECUTING","assignedAgentId":"agent-david"},{"id":"AT-104","title":"Battery thermal model v3","status":"TODO","assignedAgentId":"agent-marcus"},{"id":"AT-105","title":"Gripper force feedback tuning","status":"TODO","assignedAgentId":"agent-elena"},{"id":"AT-106","title":"Slam localization under low light","status":"REVIEW","assignedAgentId":"agent-david"},{"id":"AT-107","title":"Customer dashboard release notes","status":"DONE","assignedAgentId":"agent-marcus"},{"id":"AT-108","title":"Onboarding wizard for first-time operators","status":"DONE","assignedAgentId":"agent-elena"}],"agents":[{"id":"agent-elena","name":"Elena Rodriguez","role":"Robotics Engineer","currentStatus":"WORKING","assignedTicketId":"AT-101","initials":"ER"},{"id":"agent-marcus","name":"Marcus Webb","role":"ML Engineer","currentStatus":"WORKING","assignedTicketId":"AT-104","initials":"MW"},{"id":"agent-priya","name":"Priya Sharma","role":"DevOps Lead","currentStatus":"COMPILING","assignedTicketId":"AT-102","initials":"PS"},{"id":"agent-david","name":"David Kim","role":"Perception Engineer","currentStatus":"WORKING","assignedTicketId":"AT-103","initials":"DK"}],"channels":[{"id":"chan-atlas-launch","participants":["Elena Rodriguez","Marcus Webb","Priya Sharma"],"topic":"Atlas launch readiness","relatedTicketId":"AT-107","status":"OPEN","lastMessagePreview":"PR is up — Marcus, can you sanity-check the thermal thresholds?","messageCount":24,"updatedAt":"2026-06-28T09:14:00Z","unread":true},{"id":"chan-atlas-fw","participants":["Priya Sharma","Noah Chen","Takeshi Yamamoto"],"topic":"Firmware signing key rotation","relatedTicketId":"AT-102","status":"AWAITING_REPLY","lastMessagePreview":"Waiting on security sign-off before we can rotate keys in prod.","messageCount":11,"updatedAt":"2026-06-28T08:02:00Z"},{"id":"chan-atlas-perf","participants":["David Kim","Marcus Webb"],"topic":"p95 motion latency regression","relatedTicketId":"AT-106","status":"OPEN","lastMessagePreview":"Shadow run looks clean — bumping to 10% rollout.","messageCount":7,"updatedAt":"2026-06-27T22:41:00Z"},{"id":"chan-atlas-battery","participants":["Marcus Webb","Rafael Santos"],"topic":"Battery thermal model v3","relatedTicketId":"AT-104","status":"RESOLVED","lastMessagePreview":"Thermal model locked. Closing this out.","messageCount":19,"updatedAt":"2026-06-26T17:10:00Z"}],"activity":[{"id":"act-atlas-001","timestamp":"2026-06-28T09:14:00Z","primaryAgent":"Elena Rodriguez","action":"pushed branch","targetAgent":"Marcus Webb","context":"ankle-torque-v2 — needs thermal threshold sanity check"},{"id":"act-atlas-002","timestamp":"2026-06-28T08:55:00Z","primaryAgent":"Priya Sharma","action":"requested review from","targetAgent":"Takeshi Yamamoto","context":"OTA signing pipeline PR #482"},{"id":"act-atlas-003","timestamp":"2026-06-28T08:02:00Z","primaryAgent":"Noah Chen","action":"flagged blocker on","targetAgent":"Priya Sharma","context":"security sign-off needed for key rotation"},{"id":"act-atlas-004","timestamp":"2026-06-27T22:41:00Z","primaryAgent":"David Kim","action":"rolled out to","targetAgent":"Marcus Webb","context":"10% shadow traffic for AT-106"},{"id":"act-atlas-005","timestamp":"2026-06-27T18:12:00Z","primaryAgent":"Elena Rodriguez","action":"delegated subtask to","targetAgent":"Marcus Webb","context":"ankle torque thermal verification"},{"id":"act-atlas-006","timestamp":"2026-06-27T15:30:00Z","primaryAgent":"Marcus Webb","action":"approved PR","targetAgent":"David Kim","context":"slam-lowlight #477"},{"id":"act-atlas-007","timestamp":"2026-06-27T11:08:00Z","primaryAgent":"Priya Sharma","action":"marked blocked on","targetAgent":"Takeshi Yamamoto","context":"key rotation awaiting security approval"},{"id":"act-atlas-008","timestamp":"2026-06-26T17:10:00Z","primaryAgent":"Marcus Webb","action":"closed ticket","targetAgent":"Rafael Santos","context":"AT-104 thermal model v3 merged"},{"id":"act-atlas-009","timestamp":"2026-06-26T14:22:00Z","primaryAgent":"David Kim","action":"queued experiment for","targetAgent":"Elena Rodriguez","context":"vision-language-action sweep"},{"id":"act-atlas-010","timestamp":"2026-06-26T10:45:00Z","primaryAgent":"Elena Rodriguez","action":"split ticket into","targetAgent":"Marcus Webb","context":"AT-101 ankle calibration sub-tasks"},{"id":"act-atlas-011","timestamp":"2026-06-25T22:01:00Z","primaryAgent":"Priya Sharma","action":"deployed","targetAgent":"Elena Rodriguez","context":"AT-108 onboarding wizard to staging"},{"id":"act-atlas-012","timestamp":"2026-06-25T16:30:00Z","primaryAgent":"Marcus Webb","action":"reviewed","targetAgent":"David Kim","context":"vision-language-action benchmark PR"}]}');
INSERT INTO projects (id, workspaceId, data) VALUES ('proj-beacon', 'acme', '{"id":"proj-beacon","workspaceId":"acme","title":"Beacon Fleet","description":"Fleet coordination software that lets Atlas robots share state, divide tasks, and recover from peer failures in real time.","successCriteria":"- 50-robot fleet demo in pilot warehouse\n- Sub-second state propagation\n- Zero data loss on leader failover","color":"#50a878","status":"ACTIVE","tickets":[{"id":"BC-101","title":"Leader election under flaky network","status":"EXECUTING","assignedAgentId":"agent-noah"},{"id":"BC-102","title":"Shared SLAM map synchronization","status":"EXECUTING","assignedAgentId":"agent-james"},{"id":"BC-103","title":"Fleet dashboard rewrite in WebSocket","status":"TODO","assignedAgentId":"agent-james"},{"id":"BC-104","title":"Security audit for fleet API","status":"TODO","assignedAgentId":"agent-takeshi"},{"id":"BC-105","title":"Failover stress test report","status":"REVIEW","assignedAgentId":"agent-noah"},{"id":"BC-106","title":"Operator handoff playbook","status":"DONE","assignedAgentId":"agent-noah"}],"agents":[{"id":"agent-noah","name":"Noah Chen","role":"Fleet Coordinator","currentStatus":"WORKING","assignedTicketId":"BC-101","initials":"NC"},{"id":"agent-james","name":"James Okafor","role":"Field Engineer","currentStatus":"WORKING","assignedTicketId":"BC-102","initials":"JO"},{"id":"agent-takeshi","name":"Takeshi Yamamoto","role":"Security Engineer","currentStatus":"IDLE","assignedTicketId":"BC-104","initials":"TY"}],"channels":[{"id":"chan-beacon-lead","participants":["Noah Chen","James Okafor"],"topic":"Leader election under flaky network","relatedTicketId":"BC-101","status":"OPEN","lastMessagePreview":"Switched to Raft with 200ms heartbeat — replays are clean now.","messageCount":14,"updatedAt":"2026-06-28T07:33:00Z"},{"id":"chan-beacon-slam","participants":["James Okafor","David Kim"],"topic":"Shared SLAM map sync","relatedTicketId":"BC-102","status":"AWAITING_REPLY","lastMessagePreview":"Map diff bandwidth is 12% lower with delta encoding.","messageCount":9,"updatedAt":"2026-06-27T20:15:00Z"},{"id":"chan-beacon-sec","participants":["Takeshi Yamamoto","Noah Chen"],"topic":"Fleet API security review","relatedTicketId":"BC-104","status":"RESOLVED","lastMessagePreview":"Findings shipped, recommendations merged.","messageCount":6,"updatedAt":"2026-06-25T13:00:00Z"}],"activity":[{"id":"act-beacon-001","timestamp":"2026-06-28T07:33:00Z","primaryAgent":"Noah Chen","action":"shipped patch","targetAgent":"James Okafor","context":"BC-101 raft heartbeat at 200ms"},{"id":"act-beacon-002","timestamp":"2026-06-28T06:18:00Z","primaryAgent":"James Okafor","action":"queued experiment for","targetAgent":"Noah Chen","context":"delta-encoded SLAM maps"},{"id":"act-beacon-003","timestamp":"2026-06-27T20:15:00Z","primaryAgent":"James Okafor","action":"shared findings with","targetAgent":"David Kim","context":"slam sync bandwidth reduction"},{"id":"act-beacon-004","timestamp":"2026-06-27T15:42:00Z","primaryAgent":"Noah Chen","action":"approved","targetAgent":"James Okafor","context":"BC-105 failover stress test report"},{"id":"act-beacon-005","timestamp":"2026-06-27T11:10:00Z","primaryAgent":"Takeshi Yamamoto","action":"flagged risk on","targetAgent":"Noah Chen","context":"unauthenticated WebSocket endpoint"},{"id":"act-beacon-006","timestamp":"2026-06-26T22:30:00Z","primaryAgent":"Noah Chen","action":"split ticket","targetAgent":"James Okafor","context":"BC-102 slam sync into 3 sub-tasks"},{"id":"act-beacon-007","timestamp":"2026-06-26T16:45:00Z","primaryAgent":"James Okafor","action":"deployed","targetAgent":"Noah Chen","context":"BC-103 fleet dashboard preview"},{"id":"act-beacon-008","timestamp":"2026-06-25T13:00:00Z","primaryAgent":"Takeshi Yamamoto","action":"closed review for","targetAgent":"Noah Chen","context":"BC-104 fleet API security review"}]}');
INSERT INTO projects (id, workspaceId, data) VALUES ('proj-cortex', 'quantum', '{"id":"proj-cortex","workspaceId":"quantum","title":"Cortex Perception","description":"Vision-language-action research for unstructured environments — pick-and-place in cluttered, deformable, or low-light settings.","successCriteria":"- 90% success on unstructured pick benchmark\n- Latency under 800ms end-to-end\n- Reproducible eval pipeline","color":"#d4a84b","status":"ACTIVE","tickets":[{"id":"CX-101","title":"Deformable object grasp policy","status":"EXECUTING","assignedAgentId":"agent-zara"},{"id":"CX-102","title":"Eval harness v2 with video replay","status":"EXECUTING","assignedAgentId":"agent-fatima"},{"id":"CX-103","title":"Low-light perception fine-tune","status":"TODO","assignedAgentId":"agent-david"},{"id":"CX-104","title":"Action chunking ablation study","status":"REVIEW","assignedAgentId":"agent-zara"},{"id":"CX-105","title":"Research paper outline draft","status":"DONE","assignedAgentId":"agent-zara"}],"agents":[{"id":"agent-zara","name":"Zara Patel","role":"Research Scientist","currentStatus":"WORKING","assignedTicketId":"CX-101","initials":"ZP"},{"id":"agent-david","name":"David Kim","role":"Perception Engineer","currentStatus":"IDLE","assignedTicketId":"CX-103","initials":"DK"},{"id":"agent-fatima","name":"Fatima Al-Rashid","role":"QA Engineer","currentStatus":"COMPILING","assignedTicketId":"CX-102","initials":"FA"}],"channels":[{"id":"chan-cortex-deform","participants":["Zara Patel","David Kim"],"topic":"Deformable object grasp policy","relatedTicketId":"CX-101","status":"OPEN","lastMessagePreview":"Diffusion policy is at 78% on the cloth set — pushing to 85% by Friday.","messageCount":22,"updatedAt":"2026-06-28T08:45:00Z"},{"id":"chan-cortex-eval","participants":["Fatima Al-Rashid","Zara Patel"],"topic":"Eval harness v2","relatedTicketId":"CX-102","status":"AWAITING_REPLY","lastMessagePreview":"Need a second pass on the video replay pipeline before this lands.","messageCount":8,"updatedAt":"2026-06-27T19:20:00Z"}],"activity":[{"id":"act-cortex-001","timestamp":"2026-06-28T08:45:00Z","primaryAgent":"Zara Patel","action":"shared results with","targetAgent":"David Kim","context":"CX-101 cloth set at 78%"},{"id":"act-cortex-002","timestamp":"2026-06-28T07:10:00Z","primaryAgent":"Fatima Al-Rashid","action":"queued experiment for","targetAgent":"Zara Patel","context":"CX-102 video replay pipeline"},{"id":"act-cortex-003","timestamp":"2026-06-27T19:20:00Z","primaryAgent":"Fatima Al-Rashid","action":"requested review from","targetAgent":"Zara Patel","context":"CX-102 eval harness PR"},{"id":"act-cortex-004","timestamp":"2026-06-27T14:05:00Z","primaryAgent":"Zara Patel","action":"drafted","targetAgent":"David Kim","context":"CX-105 research paper outline"},{"id":"act-cortex-005","timestamp":"2026-06-26T11:30:00Z","primaryAgent":"David Kim","action":"queued training run","targetAgent":"Zara Patel","context":"CX-103 low-light fine-tune v2"},{"id":"act-cortex-006","timestamp":"2026-06-25T18:42:00Z","primaryAgent":"Zara Patel","action":"approved","targetAgent":"Fatima Al-Rashid","context":"CX-102 eval harness scaffolding"}]}');
INSERT INTO projects (id, workspaceId, data) VALUES ('proj-pulse', 'quantum', '{"id":"proj-pulse","workspaceId":"quantum","title":"Pulse Battery","description":"Solid-state battery optimization for 24-hour runtime — chemistry exploration, thermal modeling, and lifetime prediction.","successCriteria":"- 24h continuous operation on prototype cells\n- Cycle life above 1000 cycles at 80% capacity\n- Thermal model within 2C of physical test","color":"#7b68ee","status":"ACTIVE","tickets":[{"id":"PL-101","title":"Cycle life prediction model","status":"EXECUTING","assignedAgentId":"agent-rafael"},{"id":"PL-102","title":"Cell supplier qualification batch 3","status":"TODO","assignedAgentId":"agent-priya"},{"id":"PL-103","title":"Thermal runaway mitigation study","status":"REVIEW","assignedAgentId":"agent-rafael"},{"id":"PL-104","title":"Charging curve simulator","status":"DONE","assignedAgentId":"agent-rafael"}],"agents":[{"id":"agent-rafael","name":"Rafael Santos","role":"Hardware Engineer","currentStatus":"COMPILING","assignedTicketId":"PL-101","initials":"RS"},{"id":"agent-priya","name":"Priya Sharma","role":"DevOps Lead","currentStatus":"IDLE","assignedTicketId":"PL-102","initials":"PS"}],"channels":[{"id":"chan-pulse-thermal","participants":["Rafael Santos","Marcus Webb"],"topic":"Thermal runaway mitigation","relatedTicketId":"PL-103","status":"OPEN","lastMessagePreview":"Solid-state cells hold the line — needs one more validation cycle.","messageCount":12,"updatedAt":"2026-06-27T16:08:00Z"},{"id":"chan-pulse-supplier","participants":["Rafael Santos","Priya Sharma"],"topic":"Cell supplier qualification","relatedTicketId":"PL-102","status":"AWAITING_REPLY","lastMessagePreview":"Batch 3 samples arriving Friday — need a LabVIEW calibration update.","messageCount":5,"updatedAt":"2026-06-26T14:33:00Z"}],"activity":[{"id":"act-pulse-001","timestamp":"2026-06-28T06:50:00Z","primaryAgent":"Rafael Santos","action":"queued experiment","targetAgent":"Marcus Webb","context":"PL-101 cycle life model v4"},{"id":"act-pulse-002","timestamp":"2026-06-27T16:08:00Z","primaryAgent":"Rafael Santos","action":"shared findings with","targetAgent":"Marcus Webb","context":"PL-103 thermal runaway data"},{"id":"act-pulse-003","timestamp":"2026-06-27T10:22:00Z","primaryAgent":"Priya Sharma","action":"blocked on","targetAgent":"Rafael Santos","context":"PL-102 supplier batch lead time"},{"id":"act-pulse-004","timestamp":"2026-06-26T14:33:00Z","primaryAgent":"Rafael Santos","action":"requested calibration from","targetAgent":"Priya Sharma","context":"LabVIEW setup for batch 3"},{"id":"act-pulse-005","timestamp":"2026-06-25T11:15:00Z","primaryAgent":"Rafael Santos","action":"shipped","targetAgent":"Marcus Webb","context":"PL-104 charging curve simulator"}]}');
