INSERT INTO chat_threads (id, title, agentId, updatedAt, messages, thread_kind, project_id, workspace_id) VALUES ('chat-elena-1', 'Atlas launch readiness', 'agent-elena', '2026-07-01T01:32:28.674Z', '[{"id":"m1","role":"user","content":"What''s the status on the ankle torque controller?","timestamp":"2026-07-01T01:03:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m2","role":"assistant","content":"Pilot unit 17 calibrated yesterday at 78% confidence. Marcus is sanity-checking thermal thresholds before we roll the new curve to the full fleet. Should land by end of week.","timestamp":"2026-07-01T01:04:28.674Z","model":"opus-4.1","tokenCount":1842,"durationMs":4120},{"id":"m3","role":"user","content":"And the gripper force feedback?","timestamp":"2026-07-01T01:31:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m4","role":"assistant","content":"That''s parked until ankle lands. Force feedback depends on the torque baseline. I''ll pick it up Monday — likely 2-3 days of tuning.","timestamp":"2026-07-01T01:32:28.674Z","model":"opus-4.1","tokenCount":962,"durationMs":2210}]', 'agent', NULL, NULL);
INSERT INTO chat_threads (id, title, agentId, updatedAt, messages, thread_kind, project_id, workspace_id) VALUES ('chat-marcus-1', 'Cycle-life prediction model', 'agent-marcus', '2026-07-01T02:06:28.674Z', '[{"id":"m1","role":"user","content":"How''s PL-101 looking?","timestamp":"2026-07-01T01:50:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m2","role":"assistant","content":"v4 is mid-training. We''re seeing a 4% improvement on synthetic cycles vs v3. Real-world validation starts once the cell supplier batch 3 arrives — Priya''s tracking that.","timestamp":"2026-07-01T01:51:28.674Z","model":"opus-4.1","tokenCount":1512,"durationMs":3680},{"id":"m3","role":"user","content":"Solid. Can you sync with Rafael on the thermal model assumptions?","timestamp":"2026-07-01T02:05:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m4","role":"assistant","content":"Already on it. He''s queued the next round of thermal data for Tuesday — I''ll fold it into v5.","timestamp":"2026-07-01T02:06:28.674Z","model":"opus-4.1","tokenCount":712,"durationMs":1820}]', 'agent', NULL, NULL);
INSERT INTO chat_threads (id, title, agentId, updatedAt, messages, thread_kind, project_id, workspace_id) VALUES ('chat-luna-1', 'Onboarding wizard conversion', 'agent-luna', '2026-07-01T02:16:28.674Z', '[{"id":"m1","role":"user","content":"Conversion to first task?","timestamp":"2026-07-01T02:15:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m2","role":"assistant","content":"84% on the new flow, up from 67% on the legacy wizard. Main drop-off is at the workspace setup step — customers aren''t sure what to pick. A/B testing simpler copy next week.","timestamp":"2026-07-01T02:16:28.674Z","model":"sonnet-4.5","tokenCount":1284,"durationMs":2940}]', 'agent', NULL, NULL);
INSERT INTO chat_threads (id, title, agentId, updatedAt, messages, thread_kind, project_id, workspace_id) VALUES ('chat-david-1', 'Vision-language-action sweep', 'agent-david', '2026-07-01T02:26:28.674Z', '[{"id":"m1","role":"user","content":"Latest sweep numbers?","timestamp":"2026-07-01T02:21:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m2","role":"assistant","content":"Cloth set at 78%, deformable at 64%. Action chunking helps cloth more than rigid. Marcus is going to review the ablation tomorrow.","timestamp":"2026-07-01T02:22:28.674Z","model":"opus-4.1","tokenCount":1042,"durationMs":2510},{"id":"m3","role":"user","content":"Let''s target 85% on cloth by Friday.","timestamp":"2026-07-01T02:25:28.674Z","model":null,"tokenCount":null,"durationMs":null},{"id":"m4","role":"assistant","content":"Plan: tighter grasp priors + 2 extra fine-tune epochs. Zara will own it.","timestamp":"2026-07-01T02:26:28.674Z","model":"opus-4.1","tokenCount":612,"durationMs":1480}]', 'agent', NULL, NULL);
